# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from flask import Flask, request, jsonify, send_file, abort
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)

BASE_UPLOAD_DIR = os.path.abspath("uploads")


def resolve_path(root_dir, user_path):
    root_dir = os.path.abspath(root_dir)
    user_path = user_path or ""
    full_path = os.path.normpath(os.path.join(root_dir, user_path))
    if os.path.commonpath([root_dir, full_path]) != root_dir:
        abort(403)
    return full_path


@app.route("/list", methods=["GET"])
def list_directory():
    root = request.args.get("root", "")
    path = request.args.get("path", "")
    full_root = resolve_path(BASE_UPLOAD_DIR, root)
    target_path = resolve_path(full_root, path)

    if not os.path.exists(target_path):
        return jsonify({"error": "Path not found"}), 404
    if not os.path.isdir(target_path):
        return jsonify({"error": "Not a directory"}), 400

    items = []
    for name in os.listdir(target_path):
        item_path = os.path.join(target_path, name)
        items.append({
            "name": name,
            "type": "directory" if os.path.isdir(item_path) else "file",
            "size": os.path.getsize(item_path) if os.path.isfile(item_path) else None
        })

    return jsonify({
        "path": os.path.relpath(target_path, full_root),
        "items": items
    })


@app.route("/download", methods=["GET"])
def download_file():
    root = request.args.get("root", "")
    path = request.args.get("path", "")
    full_root = resolve_path(BASE_UPLOAD_DIR, root)
    target_path = resolve_path(full_root, path)

    if not os.path.exists(target_path):
        return jsonify({"error": "File not found"}), 404
    if not os.path.isfile(target_path):
        return jsonify({"error": "Not a file"}), 400

    return send_file(target_path, as_attachment=True)


@app.route("/info", methods=["GET"])
def file_info():
    root = request.args.get("root", "")
    path = request.args.get("path", "")
    full_root = resolve_path(BASE_UPLOAD_DIR, root)
    target_path = resolve_path(full_root, path)

    if not os.path.exists(target_path):
        return jsonify({"error": "Path not found"}), 404

    stat = os.stat(target_path)
    return jsonify({
        "name": os.path.basename(target_path),
        "path": os.path.relpath(target_path, full_root),
        "type": "directory" if os.path.isdir(target_path) else "file",
        "size": stat.st_size,
        "modified": stat.st_mtime,
        "created": stat.st_ctime
    })


if __name__ == "__main__":
    os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)
    app.run(host="0.0.0.0", port=5000, debug=True)